+          id: randomUUID(),
+          category: 'memory-poisoning',
+          source: agentId,
+          description: pattern.description,
+          evidence: [`Key: ${key}`, `Pattern: ${pattern.name}`],
+          severity: pattern.severity,
+          timestamp: now,
+          metadata: { key, patternName: pattern.name },
