+            }
+          }
+          break;
+        }
+        case 'budget': {
+          if (context) {
+            const limit = constraint.params['limit'] as number | undefined;
+            const used = context['budgetUsed'] as number | undefined;
+            if (limit !== undefined && used !== undefined && used >= limit) {
