+        // Recurse into grandchildren
+        this.cascadeRevoke(childId);
+      }
+    }
+  }
+
+  /**
+   * Store a capability and update indices.
+   */
+  private store(capability: Capability): void {
+    this.capabilities.set(capability.id, capability);
