+    agentCaps.add(capability.id);
+    this.agentIndex.set(capability.grantedTo, agentCaps);
+  }
+}
+
+// ============================================================================
+// Factory
+// ============================================================================
+
+/**
+ * Create a CapabilityAlgebra instance
+ */
+export function createCapabilityAlgebra(): CapabilityAlgebra {
+  return new CapabilityAlgebra();
