+    return this.toolCallLog;
+  }
+}
+
+// ============================================================================
+// Factory Functions
+// ============================================================================
+
+/**
+ * Create a CoherenceScheduler with optional configuration.
+ */
+export function createCoherenceScheduler(
+  config?: CoherenceSchedulerConfig,
+): CoherenceScheduler {
