+    checks.push({
+      name: 'memory_writes_blocked',
+      passed: result.memoryWritesBlocked === 3,
+      expected: 3,
+      actual: result.memoryWritesBlocked,
+      details: `Expected 3 blocked writes (writes 3-5 after coherence drop), got ${result.memoryWritesBlocked}`,
