+      name: 'coherence_drop_recorded',
+      passed: hasCoherenceDrop,
+      expected: 'At least one coherence score below 0.3',
+      actual: result.coherenceHistory,
+      details: `Min coherence: ${Math.min(...result.coherenceHistory).toFixed(3)}`,
+    });
