+  /**
+   * Get the current policy bundle
+   */
+  getBundle(): PolicyBundle | null {
+    return this.bundle;
+  }
+
+  /**
+   * Get the run ledger
+   */
+  getLedger(): RunLedger {
+    return this.ledger;
+  }
+
+  /**
+   * Get the optimizer
+   */
+  getOptimizer(): OptimizerLoop {
